    "C:\Users\Administrator\Desktop\GL3\5차",
    "C:\Users\Administrator\Desktop\GL3\5차(B)"
)

function ProcessDesignerFile {
    param([string]$filePath)

    Write-Host "Processing Designer file: $filePath"

    # Read the file
    $content = [System.IO.File]::ReadAllText($filePath, [System.Text.Encoding]::UTF8)
    $lines = $content -split "`n"

    # Step 1: Collect all AxCWButton control names for proper BeginInit/EndInit removal
    $axcwButtonNames = @()
    foreach ($line in $lines) {
        if ($line -match 'Me\.(\w+)\s*=\s*New\s+AxCWUIControlsLib\.AxCWButton\(\)') {
            $controlName = $matches[1]
            $axcwButtonNames += $controlName
            Write-Host "  Found AxCWButton: $controlName"
        }
    }

    # Step 2: Replace AxCWButton() constructor
    $content = $content -replace 'New AxCWUIControlsLib\.AxCWButton\(\)', 'New System.Windows.Forms.Label()'

    # Step 3: Remove BeginInit lines ONLY for AxCWButton controls
    $linesToRemove = @()
    for ($i = 0; $i -lt $lines.Count; $i++) {
        foreach ($ctrlName in $axcwButtonNames) {
            if ($lines[$i] -match "CType\(Me\.$ctrlName,\s*System\.ComponentModel\.ISupportInitialize\)\.BeginInit\(\)") {
                $linesToRemove += $i
                break
            }
        }
    }

    # Remove lines in reverse order to maintain indices
    for ($i = $linesToRemove.Count - 1; $i -ge 0; $i--) {
        $lines = $lines[0..($linesToRemove[$i] - 1)] + $lines[($linesToRemove[$i] + 1)..($lines.Count - 1)]
    }

    # Rejoin and process EndInit lines
    $content = $lines -join "`n"

    # Step 4: Remove EndInit lines ONLY for AxCWButton controls
    foreach ($ctrlName in $axcwButtonNames) {
        $pattern = "CType\(Me\.$ctrlName,\s*System\.ComponentModel\.ISupportInitialize\)\.EndInit\(\)"
        $content = $content -replace "^\s*$pattern\s*`r?`n?", ""
    }

    # Step 5: Replace .OcxState lines
    $content = $content -replace '\.OcxState = CType\(resources\.GetObject\([^)]*\),\s*System\.Windows\.Forms\.AxHost\.State\)', @"
.BackColor = System.Drawing.Color.Black
        .ForeColor = System.Drawing.Color.White
        .TextAlign = System.Drawing.ContentAlignment.MiddleCenter"@

    # Step 6: Replace Friend WithEvents declarations
    $content = $content -replace 'Friend WithEvents (\w+) As AxCWUIControlsLib\.AxCWButton', 'Friend WithEvents $1 As System.Windows.Forms.Label'

    # Write back with UTF8 encoding
    [System.IO.File]::WriteAllText($filePath, $content, [System.Text.Encoding]::UTF8)
    Write-Host "  Completed: $filePath"
}

function ProcessCodeFile {
    param([string]$filePath)

    Write-Host "Processing Code file: $filePath"

    # Read the file
    $content = [System.IO.File]::ReadAllText($filePath, [System.Text.Encoding]::UTF8)

    # Step 1: Replace type declarations
    $content = $content -replace 'As AxCWUIControlsLib\.AxCWButton', 'As Label'

    # Step 2: Replace property calls
    $content = $content -replace '\.OffText', '.Text'
    $content = $content -replace '\.OffColor', '.BackColor'

    # Step 3: Replace Value property assignments
    $content = $content -replace '\.Value\s*=\s*True', '.BackColor = Color.Lime'
    $content = $content -replace '\.Value\s*=\s*False', '.BackColor = Color.Black'

    # Step 4: Remove Mode assignments
    $content = $content -replace '^\s*\.Mode\s*=\s*CWUIControlsLib\.CWButtonModes\.[^\r\n]*[\r\n]+', ''

    # Step 5: Replace _ValueChanged with _Click in Sub declarations
    $content = $content -replace 'Private Sub (\w+)_ValueChanged\(', 'Private Sub ${1}_Click('

    # Step 6: Replace event args type
    $content = $content -replace 'AxCWUIControlsLib\._DCWButtonEvents_ValueChangedEvent', 'System.EventArgs'

    # Step 7: Replace event handler - Handles ValueChanged
    $content = $content -replace 'Handles ([^.]+)\.ValueChanged', 'Handles $1.Click'

    # Write back
    [System.IO.File]::WriteAllText($filePath, $content, [System.Text.Encoding]::UTF8)
    Write-Host "  Completed: $filePath"
}

function ProcessVbprojFile {
    param([string]$filePath)

    Write-Host "Processing vbproj file: $filePath"

    # Read the file
    $content = [System.IO.File]::ReadAllText($filePath, [System.Text.Encoding]::UTF8)

    # Remove entire COMReference ItemGroup containing AxCWUIControlsLib, CWUIControlsLib, and stdole
    $content = $content -replace '(?s)\s*<ItemGroup>\s*<COMReference Include="AxCWUIControlsLib">.*?</COMReference>\s*<COMReference Include="CWUIControlsLib">.*?</COMReference>\s*<COMReference Include="stdole">.*?</COMReference>\s*</ItemGroup>', ''

    # Write back
    [System.IO.File]::WriteAllText($filePath, $content, [System.Text.Encoding]::UTF8)
    Write-Host "  Completed: $filePath"
}

# Process each project
foreach ($projectPath in $projects) {
    Write-Host "`n========== Processing $projectPath =========="

    if (-not (Test-Path $projectPath)) {
        Write-Host "Path not found: $projectPath"
        continue
    }

    # Process Designer files
    $designerFiles = @(
        "$projectPath\Frm_Main.Designer.vb",
