            ProcessDesignerFile $file
        } else {
            Write-Host "File not found: $file"
        }
    }

    # Process Code files (NOT Designer)
    $codeFiles = @(
        "$projectPath\Frm_Main.vb",
        "$projectPath\Frm_Real.vb"
    )

    foreach ($file in $codeFiles) {
        if (Test-Path $file) {
            ProcessCodeFile $file
        } else {
            Write-Host "File not found: $file"
        }
    }

    # Process vbproj file
    $vbprojFile = "$projectPath\END PWR.vbproj"
    if (-not (Test-Path $vbprojFile)) {
        $vbprojFile = "$projectPath\END PWR(B).vbproj"
    }

    if (Test-Path $vbprojFile) {
        ProcessVbprojFile $vbprojFile
    } else {
        Write-Host "vbproj file not found in $projectPath"
    }
}

Write-Host "`n========== Verification =========="
Write-Host "Checking for remaining AxCW or CWUIControls references..."

foreach ($projectPath in $projects) {
    Write-Host "`nChecking $projectPath..."
    $vbFiles = Get-ChildItem -Path $projectPath -Filter "*.vb" -Recurse
    $vbprojFiles = Get-ChildItem -Path $projectPath -Filter "*.vbproj"

    $allFiles = $vbFiles + $vbprojFiles

    $foundReferences = $false
    foreach ($file in $allFiles) {
        $content = Get-Content $file.FullName -Raw
        if ($content -match 'AxCW|CWUIControls') {
            Write-Host "  Found reference in: $($file.Name)"
            $foundReferences = $true
        }
    }

    if (-not $foundReferences) {
        Write-Host "  No remaining AxCW or CWUIControls references found. OK!"
    }
}

