            $content = [System.IO.File]::ReadAllText($file, [System.Text.Encoding]::UTF8)
            $lines = $content -split "`n"
            $newLines = @()

            for ($i = 0; $i -lt $lines.Count; $i++) {
                $line = $lines[$i]

                # Fix lines that start with .ForeColor or .TextAlign without proper Me. prefix
                if ($line -match '^\s*\.ForeColor\s*=\s*System\.Drawing\.Color\.White') {
                    # Find the proper indentation from context
                    $prevLine = $lines[$i - 1]
                    if ($prevLine -match '^\s*Me\.(\w+)\.BackColor') {
                        $indent = $prevLine -replace '(^\s*)Me\..*', '$1'
                        $newLines += "$indent.ForeColor = System.Drawing.Color.White"
                    } else {
                        $newLines += $line
                    }
                } elseif ($line -match '^\s*\.TextAlign\s*=\s*System\.Drawing\.ContentAlignment\.MiddleCenter') {
                    $prevLine = $lines[$i - 1]
                    if ($prevLine -match '^\s*(Me\.|\.ForeColor)') {
                        $indent = $lines[$i - 2] -replace '(^\s*)Me\..*', '$1'
                        $newLines += "$indent.TextAlign = System.Drawing.ContentAlignment.MiddleCenter"
                    } else {
                        $newLines += $line
                    }
                } else {
                    $newLines += $line
                }
            }

